import React from 'react';
import { Line } from 'react-chartjs-2';

function Chart(props){
    //const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul','Aug', 'Sep', 'Oct', 'Nov', 'Dec']
    const months =props.tradeList.map(month => month.id.slice(0,10))
    const augProfits = props.tradeList.filter(item => {
        return item.id>= new Date('August 21,2021').getMonth(+1)
    })
    const profits = props.tradeList.map(trade => trade.profitLoss)
    console.log(augProfits)

    return(
        <div className='chart'>
            <Line
                data={{
                    labels:months,
                    datasets:[{
                        label:'Profit',
                        data:profits,
                        fill:false,
                        borderColor:'rgb(75, 192, 192)',
                        tension:0.1
                    }]
                }} />
        </div>
    )
}

export default Chart;
